files_to_process = [
    'booking-confirmation.html',
    'catalog.html',
    'my-bookings.html',
    'payment.html',
    'profile.html',
    'js/pages/catalog.js',
    'js/pages/my-bookings.js',
    'js/pages/notifications.js',
    'js/pages/profile.js'
]

base_dir = r'D:\Tes-MatchaWeb\matchaweb\src\main\resources\public'

for rel_file in files_to_process:
    filepath = os.path.join(base_dir, rel_file)
    if os.path.exists(filepath):
        with open(filepath, 'r', encoding='utf-8') as f:
            content = f.read()
        
        original_content = content
        for emoji, svg in svg_icons.items():
            if emoji in content:
                content = content.replace(emoji, svg)
        
        if content != original_content:
            with open(filepath, 'w', encoding='utf-8') as f:
                f.write(content)
            print(f'Replaced emojis in {rel_file}')
